chrome.runtime.onInstalled.addListener(()=>{console.log("Side Panel Extension installée"),chrome.storage.local.get(["links","settings"],e=>{e.links||chrome.storage.local.set({links:[]}),e.settings||chrome.storage.local.set({settings:{theme:"light",autoSave:!0}})})});chrome.action.onClicked.addListener(async e=>{try{await chrome.sidePanel.open({tabId:e.id}),console.log("Side panel toggled for tab:",e.id)}catch(o){console.error("Error toggling side panel:",o)}});chrome.runtime.onMessage.addListener((e,o,s)=>{console.log("Message reçu:",e),s({success:!0})});
